// Integration-gate cross-track contract test.
// Feeds a projection generated by the REAL Python CLI (client_reported_projection over a
// complete 6-axis bundle) through the REAL server-side validation used at publish time.
// This is the seam where the two tracks must agree byte-for-byte on canonical JSON,
// binding hashes, completeness, and composite arithmetic.
// Regenerate fixtures with: cd cli && uv run python ../scripts/gate_fixture_gen.py
import { describe, expect, it } from "vitest";
import { readFileSync } from "node:fs";
import { join } from "node:path";

import { AcceptedResultProjectionV2Schema } from "../functions/_lib/accepted-result-projection-contract";
import {
  indexV41Composite,
  isCompleteProjection,
  publishProjectionRejection,
} from "../functions/_lib/submission-publish-validation";

const FIXTURE_DIR = join(process.cwd(), "tests", "fixtures");

function loadFixture(): { projection: unknown; meta: Record<string, unknown> } {
  const projection = JSON.parse(readFileSync(join(FIXTURE_DIR, "gate-cli-projection.json"), "utf-8"));
  const meta = JSON.parse(readFileSync(join(FIXTURE_DIR, "gate-cli-projection.meta.json"), "utf-8"));
  return { projection, meta };
}

describe("gate: CLI-generated projection passes server validation", () => {
  it("parses under the server zod contract", () => {
    const { projection } = loadFixture();
    const parsed = AcceptedResultProjectionV2Schema.safeParse(projection);
    if (!parsed.success) {
      throw new Error("zod rejection: " + JSON.stringify(parsed.error.issues.slice(0, 5), null, 1));
    }
    expect(parsed.success).toBe(true);
  });

  it("is complete (all six axes measured), index-v4.1, and publish-eligible", () => {
    const { projection } = loadFixture();
    const parsed = AcceptedResultProjectionV2Schema.parse(projection);
    expect(parsed.index_version).toBe("index-v4.1");
    expect(parsed.headline_complete).toBe(true);
    expect(isCompleteProjection(parsed)).toBe(true);
    const { meta } = loadFixture();
    const row = {
      origin: parsed.origin,
      raw_bundle_sha256: meta.raw_bundle_sha256,
      suite_manifest_sha256: parsed.suite_manifest_sha256,
      suite_release_id: parsed.suite_release_id,
    } as never;
    expect(publishProjectionRejection(parsed, row)).toBeNull();
  });

  it("server composite recompute agrees with the CLI within rounding", () => {
    const { projection } = loadFixture();
    const parsed = AcceptedResultProjectionV2Schema.parse(projection);
    const serverValue = indexV41Composite(parsed);
    const clientValue = parsed.scores.headline_score;
    expect(clientValue).not.toBeNull();
    expect(Math.abs((clientValue as number) - serverValue)).toBeLessThanOrEqual(0.0005);
  });
});
